import React, { createContext, useContext, useEffect, useMemo, useReducer, useState } from 'react';
import {
  ActivityIndicator,
  Alert,
  Button,
  SafeAreaView,
  StyleSheet,
  Text,
  TextInput,
  View,
} from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';

const STORAGE_KEYS = {
  TOKEN: '@auth/token',
  USER: '@auth/user',
};

const AuthContext = createContext(null);

function authReducer(state, action) {
  switch (action.type) {
    case 'RESTORE_SESSION':
      return {
        ...state,
        token: action.payload.token,
        user: action.payload.user,
        isLoading: false,
      };
    case 'SIGN_IN':
      return {
        ...state,
        token: action.payload.token,
        user: action.payload.user,
        isLoading: false,
      };
    case 'SIGN_OUT':
      return {
        ...state,
        token: null,
        user: null,
        isLoading: false,
      };
    default:
      return state;
  }
}

async function fakeLoginApi(email, password) {
  await new Promise(resolve => setTimeout(resolve, 1000));

  if (!email || !password) {
    throw new Error('Email and password are required.');
  }

  if (password.length < 4) {
    throw new Error('Invalid credentials.');
  }

  return {
    token: `token_${Date.now()}`,
    user: {
      id: 'u1',
      name: 'MVP User',
      email,
    },
  };
}

function AuthProvider({ children }) {
  const [state, dispatch] = useReducer(authReducer, {
    token: null,
    user: null,
    isLoading: true,
  });

  useEffect(() => {
    let mounted = true;

    const restoreSession = async () => {
      try {
        const [token, userString] = await Promise.all([
          AsyncStorage.getItem(STORAGE_KEYS.TOKEN),
          AsyncStorage.getItem(STORAGE_KEYS.USER),
        ]);

        const user = userString ? JSON.parse(userString) : null;

        if (mounted) {
          dispatch({
            type: 'RESTORE_SESSION',
            payload: {
              token,
              user,
            },
          });
        }
      } catch (error) {
        if (mounted) {
          dispatch({
            type: 'RESTORE_SESSION',
            payload: {
              token: null,
              user: null,
            },
          });
        }
      }
    };

    restoreSession();

    return () => {
      mounted = false;
    };
  }, []);

  const auth = useMemo(
    () => ({
      token: state.token,
      user: state.user,
      isLoading: state.isLoading,
      isAuthenticated: !!state.token,
      signIn: async (email, password) => {
        const response = await fakeLoginApi(email, password);

        await AsyncStorage.multiSet([
          [STORAGE_KEYS.TOKEN, response.token],
          [STORAGE_KEYS.USER, JSON.stringify(response.user)],
        ]);

        dispatch({
          type: 'SIGN_IN',
          payload: response,
        });
      },
      signOut: async () => {
        await AsyncStorage.multiRemove([STORAGE_KEYS.TOKEN, STORAGE_KEYS.USER]);

        dispatch({
          type: 'SIGN_OUT',
        });
      },
      updateUser: async updatedUser => {
        await AsyncStorage.setItem(STORAGE_KEYS.USER, JSON.stringify(updatedUser));

        dispatch({
          type: 'SIGN_IN',
          payload: {
            token: state.token,
            user: updatedUser,
          },
        });
      },
    }),
    [state.token, state.user, state.isLoading]
  );

  return <AuthContext.Provider value={auth}>{children}</AuthContext.Provider>;
}

function useAuth() {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within AuthProvider');
  }
  return context;
}

function SplashScreen() {
  return (
    <SafeAreaView style={styles.centered}>
      <ActivityIndicator size="large" />
      <Text style={styles.subtitle}>Restoring session...</Text>
    </SafeAreaView>
  );
}

function LoginScreen() {
  const { signIn } = useAuth();
  const [email, setEmail] = useState('user@example.com');
  const [password, setPassword] = useState('1234');
  const [submitting, setSubmitting] = useState(false);

  const handleLogin = async () => {
    try {
      setSubmitting(true);
      await signIn(email.trim(), password);
    } catch (error) {
      Alert.alert('Login failed', error.message || 'Something went wrong');
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <SafeAreaView style={styles.container}>
      <View style={styles.card}>
        <Text style={styles.title}>Sign In</Text>

        <TextInput
          autoCapitalize="none"
          autoCorrect={false}
          keyboardType="email-address"
          placeholder="Email"
          style={styles.input}
          value={email}
          onChangeText={setEmail}
        />

        <TextInput
          secureTextEntry
          placeholder="Password"
          style={styles.input}
          value={password}
          onChangeText={setPassword}
        />

        {submitting ? (
          <ActivityIndicator />
        ) : (
          <Button title="Login" onPress={handleLogin} />
        )}
      </View>
    </SafeAreaView>
  );
}

function HomeScreen() {
  const { user, signOut, updateUser } = useAuth();

  const handleRename = async () => {
    const updatedUser = {
      ...user,
      name: 'Updated MVP User',
    };
    await updateUser(updatedUser);
    Alert.alert('Success', 'User profile updated in storage');
  };

  return (
    <SafeAreaView style={styles.container}>
      <View style={styles.card}>
        <Text style={styles.title}>Welcome</Text>
        <Text style={styles.subtitle}>Name: {user?.name}</Text>
        <Text style={styles.subtitle}>Email: {user?.email}</Text>

        <View style={styles.spacer} />
        <Button title="Update Stored User" onPress={handleRename} />
        <View style={styles.spacer} />
        <Button title="Logout" color="#c62828" onPress={signOut} />
      </View>
    </SafeAreaView>
  );
}

function AuthGate() {
  const { isLoading, isAuthenticated } = useAuth();

  if (isLoading) {
    return <SplashScreen />;
  }

  return isAuthenticated ? <HomeScreen /> : <LoginScreen />;
}

export default function App() {
  return (
    <AuthProvider>
      <AuthGate />
    </AuthProvider>
  );
}

